// src/components/ui/Card.jsx
export const Card = ({ children, title, className = "" }) => (
  <div className={`bg-[#0f172a] border border-white/10 rounded-2xl p-6 shadow-2xl shadow-black/50 ${className}`}>
    {title && (
      <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-5 border-b border-white/5 pb-2">
        {title}
      </p>
    )}
    <div className="relative z-10">
      {children}
    </div>
  </div>
);
